        if isinstance(value, int):
            return value
        elif isinstance(value, str) and value.startswith('='):
            return self.evaluate_formula(value[1:])
        else:
            return 0

    def evaluate_formula(self, formula: str) -> int:
        tokens = formula.split()
        stack = []
        for token in tokens:
            if token.isalnum() and len(token) > 1:  # Cell reference
                stack.append(self.get_cell(token))
            elif token in ('+', '-', '*', '/'):
                b = stack.pop()
                a = stack.pop()
                if token == '+':
                    stack.append(a + b)
                elif token == '-':
                    stack.append(a - b)
                elif token == '*':
                    stack.append(a * b)
                elif token == '/':
                    stack.append(a // b)  # Integer division
            else:  # Number
                stack.append(int(token))
        return stack[0] if stack else 0

